import React, { useState } from "react";
import { Outlet, NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import ProfileModal from "../shared/ProfileModal";
import toast from "react-hot-toast";
import "./Layout.css";

const navItems = [
  { to: "/student", icon: "📊", label: "Dashboard", end: true },
  { to: "/student/courses", icon: "📚", label: "Khóa học" },
  { to: "/student/schedule", icon: "📅", label: "Lớp & Lịch học" },
  { to: "/student/exercises", icon: "📝", label: "Bài tập & Kiểm tra" },
  { to: "/student/notifications", icon: "🔔", label: "Thông báo" },
  { to: "/student/history", icon: "📊", label: "Lịch sử" },
];

export default function StudentLayout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [collapsed, setCollapsed] = useState(false);
  const [showProfile, setShowProfile] = useState(false);

  const handleLogout = () => {
    logout();
    toast.success("Đã đăng xuất");
    navigate("/login");
  };

  return (
    <div className={`layout ${collapsed ? "collapsed" : ""}`}>
      <aside className="sidebar">
        <div className="sidebar-header">
          <div className="sidebar-logo">
            <span className="logo-icon">🎓</span>
            {!collapsed && <span className="logo-text">NewSky English</span>}
          </div>
          <button className="collapse-btn" onClick={() => setCollapsed(!collapsed)}>
            {collapsed ? "›" : "‹"}
          </button>
        </div>

        <nav className="sidebar-nav">
          {navItems.map(item => (
            <NavLink key={item.to} to={item.to} end={item.end}
              className={({ isActive }) => `nav-item ${isActive ? "active" : ""}`}>
              <span className="nav-icon">{item.icon}</span>
              {!collapsed && <span>{item.label}</span>}
            </NavLink>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div style={{ width: "100%", display: "flex", alignItems: "center", gap: 6 }}>
            <div className="user-info" onClick={() => setShowProfile(true)}>
              <div className="user-avatar">
                {user?.avatarUrl ? <img src={user.avatarUrl} alt="" /> : user?.name?.charAt(0)?.toUpperCase()}
              </div>
              {!collapsed && (
                <div style={{ overflow: "hidden" }}>
                  <p className="user-name">{user?.name}</p>
                  <p className="user-role">Học viên</p>
                </div>
              )}
            </div>
            <button className="logout-btn" onClick={handleLogout} title="Đăng xuất">🚪</button>
          </div>
        </div>
      </aside>

      <div className="main-wrapper">
        <header className="top-header">
          <h2 className="page-heading">Học viên</h2>
          <div className="header-right">
            <span className="welcome-text">Xin chào, {user?.name} 👋</span>
            <div className="user-avatar" style={{ cursor: "pointer" }} onClick={() => setShowProfile(true)}>
              {user?.avatarUrl ? <img src={user.avatarUrl} alt="" /> : user?.name?.charAt(0)?.toUpperCase()}
            </div>
          </div>
        </header>
        <main className="content-area"><Outlet /></main>
      </div>

      {showProfile && <ProfileModal onClose={() => setShowProfile(false)} />}
    </div>
  );
}
